import { NextResponse } from "next/server";

export function middleware(req) {
  const token = req.cookies.get("auth_token")?.value;
  const onboarding = req.cookies.get("onboarding_done")?.value;

  const url = req.nextUrl.clone();
  const path = url.pathname;

  const isAuthPage =
    path.startsWith("/login") || path.startsWith("/signup");

  // 1️⃣ Si pas connecté → rediriger vers /login
  if (!token && !isAuthPage) {
    url.pathname = "/login";
    return NextResponse.redirect(url);
  }

  // 2️⃣ Si connecté mais onboarding non fait → forcer /onboarding
  if (token && !onboarding && path !== "/onboarding") {
    url.pathname = "/onboarding";
    return NextResponse.redirect(url);
  }

  // 3️⃣ Si connecté + onboarding fait → accès normal
  return NextResponse.next();
}

export const config = {
  matcher: [
    "/((?!_next/static|_next/image|favicon.ico|api).*)",
  ],
};
